from google_adk import Agent

class FactGroundingAgent(Agent):
    def before_delegate(self, output, target_agent):
        ungrounded_claims = self.validate_claims(output)
        if ungrounded_claims:
            grounded_output = self.ground_with_retrieval(ungrounded_claims, output)
            return grounded_output
        return output

    def validate_claims(self, text):
        claims = extract_claims(text)
        return [c for c in claims if not self.verify_claim(c)]

from google_adk import Workflow

class ConsistentModelWorkflow(Workflow):
    def __init__(self):
        self.model_lock = 'gemini-2.0-flash'
        self.response_cache = {}

    def select_model(self, task):
        return self.model_lock

    def execute_task(self, task):
        cache_key = f'{task.prompt}_{self.model_lock}'
        if cache_key in self.response_cache:
            return self.response_cache[cache_key]
        result = super().execute_task(task)
        self.response_cache[cache_key] = result
        return result

